+import { isAspect, type Aspect } from '../aspect/aspect';
+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { isRelationPair } from '../relation/utils/is-relation';
+import type { Relation } from '../relation/types';
+import { Store } from '../storage';
+import { getStore } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import { isModifier } from './modifier';
+import { setChanged } from './modifiers/changed';
+import type {
+    InstancesFromParameters,
+    QueryInstance,
+    QueryParameter,
+    QueryResult,
+    QueryResultOptions,
+    StoresFromParameters,
+} from './types';
+
+type Entry = { traits: Trait[]; aspect?: Aspect };
+
+export function createQueryResult<T extends QueryParameter[]>(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+): QueryResult<T> {
+    let entries = getEntries(params);
+    const results = Object.assign(entities, {
+        readEach(callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) {
+                callback(readState(world, entities[i], entries) as InstancesFromParameters<T>, entities[i], i);
+            }
+            return results;
+        },
+        updateEach(
+            callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void,
+            options: QueryResultOptions = { changeDetection: 'auto' }
+        ) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readState(world, entity, entries);
+                callback(state as InstancesFromParameters<T>, entity, i);
+                if (!world.has(entity)) continue;
+                writeState(world, entity, entries, state, query, options.changeDetection ?? 'auto');
+            }
+            return results;
+        },
+        useStores(callback: (stores: StoresFromParameters<T>, entities: readonly Entity[]) => void) {
+            callback(
+                entries.flatMap((entry) => entry.traits.filter(notTag).map((trait) => getStore(world, trait))) as StoresFromParameters<T>,
+                entities
+            );
+            return results;
+        },
+        select<U extends QueryParameter[]>(...selected: U): QueryResult<U> {
+            entries = getEntries(selected);
+            return results as unknown as QueryResult<U>;
+        },
+        sort(
+            callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)
+        ): QueryResult<T> {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<T>;
+}
+
+function getEntries(params: QueryParameter[]): Entry[] {
+    const entries: Entry[] = [];
+    for (const param of params) {
+        if (isRelationPair(param)) {
+            const trait = (param[$internal].relation as Relation<Trait>)[$internal].trait;
+            if (notTag(trait)) entries.push({ traits: [trait] });
+        } else if (isModifier(param)) {
+            if (param.type !== 'not') {
+                for (const component of param.components) {
+                    if (isAspect(component)) entries.push({ traits: component.traits, aspect: component });
+                    else if (notTag(component)) entries.push({ traits: [component] });
+                }
+            }
+        } else if (isAspect(param)) {
+            entries.push({ traits: param.traits, aspect: param });
+        } else if (notTag(param)) {
+            entries.push({ traits: [param] });
+        }
+    }
+    return entries;
+}
+
+function readState(world: World, entity: Entity, entries: Entry[]) {
+    const eid = getEntityId(entity);
+    return entries.map((entry) => {
+        const values = entry.traits.filter(notTag).map((trait) => trait[$internal].get(eid, getStore(world, trait)));
+        return entry.aspect ? Object.assign({}, ...values) : values[0];
+    });
+}
+
+function writeState(
+    world: World,
+    entity: Entity,
+    entries: Entry[],
+    state: any[],
+    query: QueryInstance,
+    changeDetection: NonNullable<QueryResultOptions['changeDetection']>
+) {
+    const eid = getEntityId(entity);
+    for (let i = 0; i < entries.length; i++) {
+        const entry = entries[i];
+        for (const trait of entry.traits) {
+            if (!notTag(trait)) continue;
+            const next = entry.aspect ? pickFields(trait, state[i]) : state[i];
+            const ctx = trait[$internal];
+            const store = getStore(world, trait);
+            const tracked = world[$internal].trackedTraits.has(trait) || query.changedTraits.has(trait);
+            const changed = changeDetection !== 'never' && (changeDetection === 'always' || tracked)
+                ? ctx.fastSetWithChangeDetection(eid, store, next)
+                : (ctx.fastSet(eid, store, next), false);
+            if (changed) setChanged(world, entity, trait);
+        }
+    }
+}
+
+function pickFields(trait: Trait, value: Record<string, any>) {
+    const result: Record<string, any> = {};
+    for (const key of Object.keys(trait.schema)) if (key in value) result[key] = value[key];
+    return result;
+}
+
+function notTag(trait: Trait) {
+    return trait[$internal].type !== 'tag';
+}
+
+export function getQueryStores<T extends QueryParameter[]>(
+    params: T,
+    traits: Trait[],
+    stores: Store<any>[],
+    world: World
+) {
+    for (const entry of getEntries(params)) {
+        for (const trait of entry.traits) if (notTag(trait)) {
+            traits.push(trait);
+            stores.push(getStore(world, trait));
+        }
+    }
+}
+
+export function createEmptyQueryResult(): QueryResult<QueryParameter[]> {
+    const results = Object.assign([], {
+        readEach: () => results,
+        updateEach: () => results,
+        useStores: () => results,
+        select: () => results,
+        sort: () => results,
+    }) as QueryResult<QueryParameter[]>;
+    return results;
+}
+
+export function createRelationOnlyQueryResult<T extends QueryParameter[]>(entities: Entity[]): QueryResult<T> {
+    return createQueryResult({} as World, entities, {} as QueryInstance, []) as QueryResult<T>;
+}
