function addAspect(world: World, entity: Entity, aspect: Aspect, value?: Record<string, any>) {
    for (const trait of aspect.traits) {
        if (hasTrait(world, entity, trait)) continue;
        const params = getAspectTraitValue(trait, value);
        addTrait(world, entity, Object.keys(params).length ? [trait, params] : trait);
    }
